WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/9.0/connection.js")} 

var records = {!GETRECORDIDS( $ObjectType.pd_jp_20151124__CsvExport__c)}; 

if (records[0] == null) { 
alert("少なくとも1レコードは選択してください。") } 
else { 

var errors = []; 
var result = sforce.connection.deleteIds(records); 
if (result && result.length){ 
var numFailed = 0; 
var numSucceeded = 0; 
for (var i = 0; i < result.length; i++){ 
var res = result[i]; 
if (res && res.success == 'true'){ 
numSucceeded++; 
} else { 
var es = res.getArray("errors"); 
if (es.length > 0) { 
errors.push(es[0].message); 
} 
numFailed++; 
} 
} 
if (numFailed > 0){ 
alert("失敗数: " + numFailed + "\n成功数: " + numSucceeded + " \n エラー理由: " + errors.join("\n")); 
} else { 
alert("レコードの削除に成功しました。削除レコード数: " + numSucceeded); 
} 
} 
window.location.reload(); 
}
